async function seedAiAgents(userId = 1) {
  const db = getDb();
  let created = 0;
  let renamed = 0;
  try {
    const existing = await db.select().from(aiAgentConfigs).where(eq2(aiAgentConfigs.userId, userId));
    const byName = new Map(existing.map((r) => [r.name, r]));
    for (const a of AGENTS) {
      if (byName.has(a.name)) continue;
      const alias = (a.aliases ?? []).map((n) => byName.get(n)).find(Boolean);
      if (alias) {
        await db.update(aiAgentConfigs).set({ name: a.name, agentType: a.agentType, description: a.description }).where(and(eq2(aiAgentConfigs.id, alias.id), eq2(aiAgentConfigs.userId, userId)));
        renamed++;
        continue;
      }
      await db.insert(aiAgentConfigs).values({
        userId,
        name: a.name,
        agentType: a.agentType,
        description: a.description,
        model: a.model,
        systemPrompt: a.systemPrompt,
        capabilities: JSON.stringify(a.capabilities),
        isActive: true,
        autoRun: false
      });
      created++;
    }
    if (created || renamed) console.log(`[seed] ai agents: +${created} created, ${renamed} renamed to named roster`);
  } catch (e) {
    console.error("[seed] seedAiAgents failed (non-fatal):", e instanceof Error ? e.message : e);
  }
  return { created, renamed };
}
