var bulkImportRouter = createRouter({
  importClients: publicQuery.input(external_exports.object({ token: external_exports.string() })).mutation(async ({ input }) => {
    if (!checkSecret(input.token, "BULK_IMPORT_TOKEN")) {
      throw new Error("Invalid token");
    }
    const db = getDb();
    const results = { imported: 0, skipped: 0, tasksCreated: 0, errors: [] };
    for (const clientData of CLIENTS_DATA) {
      try {
        const existing = await db.select().from(clients).where(eq2(clients.name, clientData.name)).limit(1);
        if (existing.length > 0) {
          results.skipped++;
          continue;
        }
        const [client] = await db.insert(clients).values({
          ...clientData,
          userId: 1,
          // Markie's user ID
          createdAt: /* @__PURE__ */ new Date(),
          updatedAt: /* @__PURE__ */ new Date()
        }).returning();
        results.imported++;
        if (client) {
          const taskResult = await ensureComplianceForClient(client.id, { userId: 1, assignedTo: clientData.assignedTo });
          results.tasksCreated += taskResult?.tasks || 0;
        }
      } catch (e) {
        results.errors.push(`${clientData.name}: ${e.message}`);
      }
    }
    return {
      success: true,
      ...results,
      totalClients: CLIENTS_DATA.length
    };
  })
});

