  const [y, m] = firstMonthKey.split("-").map((s) => parseInt(s, 10));
  const out = [];
  for (let i = 0; i < 12; i++) {
    const mm = (m - 1 + i) % 12 + 1;
    const yy = y + Math.floor((m - 1 + i) / 12);
    out.push(`${yy}-${String(mm).padStart(2, "0")}`);
  }
